const allRows = $input.all();
const newLeads = allRows.filter(function(row) {
  const status = (row.json['status'] || '').trim();
  return status === 'New Lead';
});
console.log('New leads to process: ' + newLeads.length + ' of ' + allRows.length + ' total rows');
const cleanLeads = newLeads.map(function(item) {
  const cleaned = {};
  const keys = Object.keys(item.json);
  for (let i = 0; i < keys.length; i++) {
    if (keys[i] !== 'json') {
      cleaned[keys[i]] = item.json[keys[i]];
    }
  }
  return { json: cleaned };
});
return cleanLeads;

const allItems = $input.all();
const output = [];
for (let i = 0; i < allItems.length; i++) {
  const lead = allItems[i].json;
  const bio = (lead['Notes'] || '').trim();
  const businessName = (lead['Business Name'] || lead['Instagram Handle'] || 'there').trim();
  const industry = (lead['Type'] || 'business').trim();
  const location = (lead['Location'] || 'London').trim();
  const followers = lead['Followers'] || 'unknown';
  const prompt = 'You are writing a cold Instagram DM opener for a sales outreach campaign.\nLead details:\n- Business Name: ' + businessName + '\n- Industry: ' + industry + '\n- Location: ' + location + '\n- Bio: ' + (bio || 'No bio available') + '\n- Followers: ' + followers + '\n\nWrite ONE short opener DM using this exact formula:\n"Hey [Business Name] - saw [something specific from their bio or profile]. [One genuine observation about it]. Would this be the best place to ask you a quick question?"\n\nRules:\n- Reference something REAL and SPECIFIC from the bio\n- The observation must be genuine\n- Under 3 lines total\n- NEVER mention AI, automation, agencies, or technology\n- NEVER use generic compliments (no "Love what you're doing", "Amazing", "Great work", etc)\n- NEVER include a compliment of any kind — no "love that", "great that", "impressive that", "rare to see", "good to see". State what you noticed, not how you feel about it.\n- End with ONE question only\n- If no useful bio info: output exactly "REVIEW NEEDED - add profile detail before sending"\n\nOutput the DM text only. No explanation. No surrounding quotes.';
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': 'YOUR_ANTHROPIC_API_KEY',
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: {
      model: 'claude-haiku-4-5',
      max_tokens: 150,
      messages: [{ role: 'user', content: prompt }]
    },
    json: true
  });
  const opener = response.content[0].text.trim();
output.push({
  json: {
    row_number: lead['row_number'],
    business_name: businessName,
    status: 'Opener Generated',
    opener: opener,
    generated_at: new Date().toISOString().split('T')[0]
  }
});
}
return output;

const items = $input.all();
const openerLines = items.map(function(item, i) {
  const handle = item.json.instagram_handle || 'unknown';
  const name = (item.json.business_name || handle).trim();
  const type = item.json.industry || '';
  const opener = item.json.opener || '';
  const needsReview = opener.startsWith('REVIEW NEEDED');
  const flag = needsReview ? ' [NEEDS REVIEW]' : '';
  return (i + 1) + '. ' + name + ' (' + handle + ') - ' + type + flag + '\n   ' + opener;
});

const reviewCount = items.filter(function(i) {
  return (i.json.opener || '').startsWith('REVIEW NEEDED');
}).length;
const readyCount = items.length - reviewCount;
const date = new Date().toISOString().split('T')[0];
const subject = 'Zizi - ' + items.length + ' opener' + (items.length !== 1 ? 's' : '') + ' ready (' + date + ')';
const body = 'Workflow 2 - Opener Generation Complete\nDate: ' + date + '\nTotal processed: ' + items.length + '\nReady to send: ' + readyCount + '\nNeeds manual review: ' + reviewCount + '\n---\n' + openerLines.join('\n\n') + '\n---\nAll openers written to Google Sheet under "opener" column.\nStatus updated to "Opener Generated".\nZizi: review each opener, personalise if needed, then send from the lead\'s profile.\nFlag anything that looks wrong before sending.';

return [{
  json: {
    subject: subject,
    body: body,
    count: items.length,
    ready: readyCount,
    review: reviewCount
  }
}];
